<style>
  .bug-illustration-wrapper {
    position: absolute;
    bottom: -40px;
    right: -70px;
    width: 280px;
    height: auto;
    z-index: 1; /* Keep behind text */
    pointer-events: none;
  }

  .bug-svg {
    width: 100%;
    height: 100%;
    display: block;
    filter: drop-shadow(0 0 20px rgba(138, 43, 226, 0.2));
  }

  /* Aesthetic Color Mapping */
  .dark-base {
    fill: #0a0a0c;
    stroke: #1a1a1f;
    stroke-width: 10px;
  }
  .accent-primary {
    fill: var(--primary, #8a2be2);
  }
  .accent-secondary {
    fill: var(--secondary, #00ffff);
  }
  .glass-fill {
    fill: rgba(0, 255, 255, 0.15);
  }

  /* Default Staggered Animations */
  .arm-magnifier-group {
    transform-origin: 30% 70%;
    animation: gentle-sway 6s ease-in-out infinite;
  }
  .bug-group {
    transform-origin: 50% 50%;
    animation: bug-float 4s ease-in-out infinite reverse;
  }
  .hair-group {
    transform-origin: 60% 40%;
    animation: breeze 5s ease-in-out infinite;
  }

  @keyframes gentle-sway {
    0%, 100% { transform: rotate(0deg) translate(0, 0); }
    50% { transform: rotate(-2deg) translate(20px, -15px); }
  }

  @keyframes bug-float {
    0%, 100% { transform: translate(0, 0); }
    50% { transform: translate(-10px, 20px); }
  }

  @keyframes breeze {
    0%, 100% { transform: rotate(0deg); }
    50% { transform: rotate(1deg); }
  }

  /* Hover State Animations */
  .hovering .arm-magnifier-group {
    animation: search-down 1.5s cubic-bezier(0.25, 0.8, 0.25, 1) forwards;
  }

  .hovering .bug-group {
    animation: bug-shrink-bounce 1s cubic-bezier(0.68, -0.55, 0.27, 1.55) forwards;
    animation-delay: 0.3s;
  }

  @keyframes search-down {
    0% { transform: rotate(0deg) translate(0, 0); }
    40% { transform: rotate(-4deg) translate(40px, 80px); }
    100% { transform: rotate(-2deg) translate(20px, 60px); }
  }

  @keyframes bug-shrink-bounce {
    0% { transform: scale(1) translate(0, 0); }
    50% { transform: scale(0.6) translate(-50px, 150px); }
    100% { transform: scale(0.8) translate(-20px, 80px); }
  }
</style>
